import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { toast } from 'react-toastify';

// Import the centralized API instance from your axiosConfig.js
// Assuming axiosConfig.js is directly in the src folder
import API from '../axiosConfig'; // Adjust path if axiosConfig.js is elsewhere, e.g., '../api/axiosConfig'

// MediaDisplay component now uses the same base URL as the API
const MediaDisplay = ({ src, type, alt, className }) => {
  if (!src) return null;
  // Use the baseURL from the imported API instance
  const fullSrc = `${API.defaults.baseURL.replace('/api', '')}${src}`; // Remove '/api' for media assets

  const handleError = (e) => {
    e.target.onerror = null;
    e.target.style.display = 'none'; // Hide broken media links
  };

  if (type === 'image') {
    return <img src={fullSrc} alt={alt} className={className} onError={handleError} />;
  }
  if (type === 'audio') {
    return (
      <audio controls src={fullSrc} className={className} onError={handleError}>
        Your browser does not support the audio element.
      </audio>
    );
  }
  return null;
};

export default function ViewAnswer() {
  const { attemptId } = useParams();
  const [reviewData, setReviewData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchAttemptReview = async () => {
      // Add this check: Stop if the ID is missing or is the literal string "undefined"
      if (!attemptId || attemptId === 'undefined') {
        setError("Cannot load review. The attempt ID is missing.");
        toast.error("Cannot load review: Attempt ID is missing.");
        setLoading(false);
        return;
      }

      try {
        setLoading(true);
        // Use the centralized API instance
        // Assuming your backend review endpoint is /exam-review/:examAttemptId
        // If your backend still uses /exam-history/:userId/:examAttemptId, you'll need to pass userId here too
        const res = await API.get(`/exam-review/${attemptId}`); // Adjusted to match your frontend call
        setReviewData(res.data);
      } catch (err) {
        console.error("Error fetching exam review:", err);
        const errorMessage = err.response?.data?.message || "Failed to load the exam review.";
        setError(errorMessage);
        toast.error(`Failed to load review: ${errorMessage}`);
      } finally {
        setLoading(false);
      }
    };

    fetchAttemptReview();
  }, [attemptId]);

  if (loading) return (
    <div className="flex items-center justify-center h-screen">
      <div className="text-xl font-semibold">Loading Review...</div>
    </div>
  );

  if (error) return (
    <div className="max-w-4xl p-4 mx-auto text-center text-red-500">
      <h2 className="text-2xl font-bold">Error</h2>
      <p className="mt-2">{error}</p>
      <Link to="/answer" className="inline-block px-4 py-2 mt-4 text-white bg-blue-600 rounded-md hover:bg-blue-700">
        Go to Exam Page
      </Link>
    </div>
  );

  if (!reviewData) return <div className="mt-4 text-center text-gray-500">Attempt review not found.</div>;

  // Destructure reviewData from the backend response
  const { category, section, set, answers } = reviewData; // Note: 'answers' is the array of questions with user's choices

  return (
    <div className="max-w-3xl p-6 mx-auto my-8 bg-white rounded-lg shadow-md">
      <h2 className="mb-4 text-2xl font-bold text-center text-gray-800">
        Exam Review: {set}
      </h2>
      <h3 className="mb-6 text-lg font-medium text-center text-gray-600">
        {category} &gt; {section}
      </h3>

      <div className="space-y-6">
        {answers.map((answerItem, qIndex) => { // Iterate over 'answers' array
          const question = answerItem.questionId; // Each 'answerItem' has 'questionId' populated as the full question
          if (!question) return null; // Handle cases where questionId might not be populated

          const userSelectedOption = answerItem.selectedOption; // User's selected option for this question
          const isCorrectGlobal = answerItem.isCorrect; // Whether the user's answer was correct

          return (
            <div key={question._id || qIndex} className="p-4 border border-gray-200 rounded-md bg-gray-50">
              <p className="mb-2 text-lg font-semibold">Q{qIndex + 1}: {question.questionText}</p>
              <MediaDisplay
                src={question.questionImage}
                type="image"
                alt="Question visual"
                className="h-auto max-w-full mb-2 rounded-md"
              />
              <MediaDisplay
                src={question.questionAudio}
                type="audio"
                className="w-full mb-2"
              />
              <ul className="pl-5 mt-4 space-y-2 list-none">
                {question.options.map((option, oIndex) => {
                  const optionLetter = String.fromCharCode(97 + oIndex);
                  const isCorrectAnswerOption = optionLetter === question.correctAnswer;
                  const isUserAnswerOption = optionLetter === userSelectedOption;

                  let liClassName = 'p-3 rounded-lg border-2';
                  if (isCorrectAnswerOption) {
                    liClassName += ' bg-green-100 border-green-500';
                  } else if (isUserAnswerOption) { // Only mark red if it's the user's answer AND not the correct one
                    liClassName += ' bg-red-100 border-red-500';
                  } else {
                    liClassName += ' bg-white border-gray-300';
                  }

                  return (
                    <li key={oIndex} className={liClassName}>
                      <div className="flex items-center">
                        <span className="font-bold">{String.fromCharCode(65 + oIndex)}.</span>
                        <div className="ml-3">
                          {option.type === 'text' && <span>{option.content}</span>}
                          <MediaDisplay
                            src={option.content}
                            type={option.type}
                            alt={`Option ${String.fromCharCode(65 + oIndex)}`}
                            className={option.type === 'image' ? "inline-block max-w-[100px] max-h-[100px] rounded" : "inline-block w-full"}
                          />
                        </div>
                      </div>
                      <div className="mt-2 text-sm font-semibold">
                        {isCorrectAnswerOption && <span className="text-green-700">(Correct Answer)</span>}
                        {isUserAnswerOption && !isCorrectAnswerOption && <span className="ml-2 text-red-700">(Your Answer)</span>}
                        {isUserAnswerOption && isCorrectAnswerOption && <span className="ml-2 text-green-700">(Your Answer)</span>}
                      </div>
                    </li>
                  );
                })}
              </ul>
              {userSelectedOption === null && ( // Check if user didn't select an option for this question
                <p className="p-2 mt-4 text-sm font-semibold text-yellow-800 bg-yellow-100 rounded-md">
                  You did not answer this question.
                </p>
              )}
            </div>
          );
        })}
      </div>

      <div className="mt-8 text-center">
        <Link to="/answer" className="w-full px-6 py-3 font-medium text-white bg-indigo-600 rounded-md hover:bg-indigo-700">
          Start a New Exam
        </Link>
      </div>
    </div>
  );
}
